WHERE categoryno=#{categoryno} AND (UPPER(title) LIKE '%' || UPPER(#{word}) || '%' OR UPPER(content) LIKE '%' || UPPER(#{word}) || '%' OR UPPER(word) LIKE '%' || UPPER(#{word}) || '%')

mapper.update:
UPDATE board
SET title=#{title}, content=#{content},  word=#{word}
WHERE boardno = #{boardno}

UPDATE board
SET file1=#{file1}, file1saved=#{file1saved}, thumb1=#{thumb1}, size1=#{size1}
WHERE boardno = #{boardno}

UPDATE board
SET recom = recom + 1
WHERE boardno = #{boardno}

UPDATE board
SET recom = recom - 1
WHERE boardno = #{boardno}

UPDATE board
SET replycnt = replycnt + 1
WHERE boardno = #{boardno}

UPDATE board
SET replycnt = replycnt - 1
WHERE boardno = #{boardno}
